function formatDate(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  const yyyy = d.getFullYear();
  return `${mm}-${dd}-${yyyy}`;
}

function parseDate(d) {
  if (!d) return null;
  const dt = new Date(d);
  return isNaN(dt) ? null : dt;
}

// --------------------
// Filter by status tab (ALWAYS applied)
// --------------------
let filteredData = selectedStatus
  ? data.filter(r => {
      const raw = (r.current_status || "").toLowerCase().trim();
      const normalized = raw.replace(/^\d+\s*-\s*/, "").trim();
      const tab = selectedStatus.toLowerCase().trim();

      return (
        raw === tab ||
        normalized === tab ||
        raw.includes(tab) ||
        normalized.includes(tab)
      );
    })
  : data;

// --------------------
// Filter by fabricator
// --------------------
filteredData = filteredData.filter(r =>
  fabricatorFilter === 'ALL' ||
  r.assigned_shop === fabricatorFilter
);

// --------------------
