const totalPackages = filteredData.length;

const totalWeldInches = filteredData.reduce(
  (sum, r) => sum + (r.total_weld_inches || 0),
  0
);

const totalFabHours = filteredData.reduce(
  (sum, r) => sum + (r.estimated_fab_hours || 0),
  0
);

const pastDue = filteredData.filter(r => {
  const date = parseDate(r.date_needed);
  return date && date < today;
}).length;

// --------------------
