// --------------------
const futurePackages = filteredData
  .filter(r => {
    const date = parseDate(r.date_needed);
    return date && date >= today;
  })
  .sort((a, b) => new Date(a.date_needed) - new Date(b.date_needed));

const nextDue = futurePackages.length > 0 ? futurePackages[0] : null;

// --------------------
// Find most recent past-due package
// --------------------
const pastPackages = filteredData
  .filter(r => {
    const date = parseDate(r.date_needed);
    return date && date < today;
  })
  .sort((a, b) => new Date(b.date_needed) - new Date(a.date_needed));

const lastPastDue = pastPackages.length > 0 ? pastPackages[0] : null;

// --------------------
// Return stats object
// --------------------
return {
  totalPackages,
  totalWeldInches,
  totalFabHours,
  pastDue,
  nextDue: nextDue
    ? { ...nextDue, formatted_date_needed: formatDate(nextDue.date_needed) }
    : null,
  lastPastDue: lastPastDue
    ? { ...lastPastDue, formatted_date_needed: formatDate(lastPastDue.date_needed) }
    : null
};

