const data = {{ allPackagesTransformer.value || [] }};

const search = {{ textInput2.value?.toLowerCase().trim() || '' }};
const activeTab = {{ tabbedContainer2.currentViewKey?.trim() }};

const projectFilter = {{ projectFilter.value || 'ALL' }};
const fabricatorFilter = {{ fabricatorFilter.value || 'ALL' }};

