    projectFilter === 'ALL' ||
    p.project_name === projectFilter;

  // 🏭 Fabricator match
  const matchesFabricator =
    fabricatorFilter === 'ALL' ||
    p.assigned_shop === fabricatorFilter;

  return (
    matchesSearch &&
    matchesStatus &&
    matchesProject &&
    matchesFabricator
  );
});

